   372→                Text("朗读")
   373→            }
   374→            Button(onClick = {
   375→                answers.forEachIndexed { i, answer ->
   376→                    results[i] = if (inputs[i].trim().equals(answer, ignoreCase = true)) "correct" else "wrong"
   377→                }
   378→            }) {
   379→                Icon(Icons.Default.Check, null, Modifier.size(16.dp))
   380→                Spacer(Modifier.width(4.dp))
   381→                Text("检查")
   382→            }
   383→            Button(onClick = {
