    47→@HiltViewModel
    48→class PlayerViewModel @Inject constructor(
    49→    application: Application,
    50→    private val favoriteRepository: FavoriteRepository,
    51→    private val aiConfigStore: AIConfigStore,
    52→    private val aiService: AIService,
    53→    private val dictionaryService: DictionaryService,
