    71→    fun loadSubtitles(videoPath: String, subtitlePath: String?) {
    72→        viewModelScope.launch(Dispatchers.IO) {
    73→            // Try loading VTT subtitle
    74→            val vttPath = subtitlePath ?: findExistingSubtitle(videoPath)
    75→            if (vttPath != null) {
    76→                val file = File(vttPath)
    77→                if (file.exists()) {
    78→                    val content = file.readText()
    79→                    val subs = VttParser.parse(content)
    80→                    if (subs.isNotEmpty()) {
    81→                        _uiState.update { it.copy(
    82→                            subtitles = subs,
    83→                            statusText = "已加载 ${subs.size} 条字幕"
    84→                        )}
    85→                        // Load word timestamps if available
    86→                        loadWordTimestamps(vttPath)
    87→                        return@launch
    88→                    }
    89→                }
    90→            }
    91→            _uiState.update { it.copy(statusText = "无字幕文件，请在 AI 设置中配置 Groq Whisper 后重新转录") }
    92→        }
    93→    }
