    95→    private fun findExistingSubtitle(videoPath: String): String? {
    96→        val base = videoPath.substringBeforeLast(".")
    97→        for (ext in listOf(".vtt", ".srt")) {
    98→            val f = File(base + ext)
    99→            if (f.exists()) return f.absolutePath
   100→        }
   101→        // Check with language suffix
   102→        val dir = File(videoPath).parentFile ?: return null
   103→        val name = File(videoPath).nameWithoutExtension
   104→        dir.listFiles()?.forEach { f ->
   105→            if (f.name.startsWith(name) && f.extension == "vtt") return f.absolutePath
   106→        }
   107→        return null
   108→    }
   109→
   110→    private fun loadWordTimestamps(vttPath: String) {
   111→        val wtsPath = vttPath.replace(Regex("\\.vtt$"), ".wordts.json")
   112→        val wtsFile = File(wtsPath)
   113→        if (wtsFile.exists()) {
   114→            try {
   115→                val timings: List<WordTimestamp> = json.decodeFromString(wtsFile.readText())
   116→                _uiState.update { it.copy(wordTimings = timings) }
   117→            } catch (_: Exception) {}
   118→        }
   119→    }
   120→
   121→    /** Called every 30ms from the player to sync subtitles */
   122→    fun updatePosition(positionMs: Long) {
   123→        _uiState.update { it.copy(currentPositionMs = positionMs) }
   124→        val subs = _uiState.value.subtitles
   125→        if (subs.isEmpty()) return
   126→
   127→        // Binary search for current cue (ported from renderer.js)
   128→        var lo = 0; var hi = subs.size - 1; var idx = -1
   129→        while (lo <= hi) {
   130→            val mid = (lo + hi) ushr 1
   131→            when {
   132→                positionMs < subs[mid].startMs -> hi = mid - 1
   133→                positionMs > subs[mid].endMs -> lo = mid + 1
   134→                else -> { idx = mid; break }
   135→            }
   136→        }
   137→        // Gap handling: find next cue within 0.5s
   138→        if (idx < 0) {
   139→            for (i in subs.indices) {
   140→                if (subs[i].startMs > positionMs) {
   141→                    idx = if (subs[i].startMs - positionMs < 500) i else if (i > 0) i - 1 else 0
   142→                    break
   143→                }
   144→            }
   145→            if (idx < 0) idx = subs.size - 1
   146→        }
   147→
   148→        if (idx != _uiState.value.currentCueIndex) {
   149→            _uiState.update { it.copy(
   150→                currentCueIndex = idx,
   151→                currentSentence = subs[idx].text,
   152→                showWordCard = false,
   153→                aiAnalysisResult = null
   154→            )}
   155→        }
   156→    }
